from langchain.memory import ConversationBufferMemory
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.runnables import RunnableLambda

memory = ConversationBufferMemory(return_messages=True)
prompt = ChatPromptTemplate.from_messages([
    ("system", "You are helpful."),
    ("placeholder", "{history}"),
    ("user", "{question}"),
])

def mock_llm(msgs):
    return {"text": "ok"}

chain = prompt | RunnableLambda(lambda m: mock_llm(m.to_messages()))

def chat(user_text: str):
    try:
        # BUG: post-0.2 upgrade, buffer_as_messages attribute no longer exists
        response = chain.invoke({"question": user_text, "history": memory.buffer_as_messages})
        memory.save_context({"input": user_text}, {"output": response["text"]})
        return response
    except AttributeError as e:
        raise RuntimeError(f"memory access failed: {e}") from e

if __name__ == '__main__':
    chat("hello")
